const DATA = {"nodes": [{"id": "n_root", "parent_id": null, "evidence_quality": "well-evidenced", "label": "What does the evidence say about immigration's effects on the host country \u2014 and on which dimension?", "children": ["n_econ", "n_fiscal", "n_innov", "n_social"], "role": "topic", "question": {"research": "What does the evidence say about immigration's effects on the host country \u2014 and on which dimension?", "simple": "Is immigration good or bad for the country it moves to?"}, "depends_on": {"research": "'Net beneficial' is not one measurable quantity. The literature measures separate dimensions; pick one. The global verdict is a values-weighted sum of these, not an empirical result.", "simple": "There's no single 'good or bad' score. Studies measure separate areas; pick one. Your overall view depends on how much each area matters to you."}, "coverage_note": "Authored dimensions: labour market, public finances, innovation, social outcomes. DELIBERATELY NOT COVERED (invisible to this tool): housing & rents, congestion of public services, gains to employers/capital owners (the counterpart to any wage effect), effects on origin countries (brain drain / remittances), and political/electoral effects. Absence is a scope choice, not evidence of no effect.", "scored": false, "evidence_caveats": ["recency: OECD-migration (2016) \u226510y old \u2014 refresh review", "recency: NAS-2016 (2016) \u226510y old \u2014 refresh review"]}, {"id": "n_econ", "parent_id": "n_root", "evidence_quality": "well-evidenced", "label": "How does immigration affect the host labour market and economic output?", "children": ["n_econ_wages_overall", "n_econ_wages_lowskill", "n_econ_gdp_pc"], "role": "dimension", "question": {"research": "How does immigration affect the host labour market and economic output?", "simple": "How does immigration affect jobs, pay, and the economy?"}, "depends_on": {"research": "Depends on WHICH workers (all natives vs the low-skilled natives & prior immigrants who are closest substitutes) and WHICH metric (aggregate GDP vs GDP per capita).", "simple": "Depends on which workers you mean (everyone, or the lower-paid who compete most) and which measure (the economy's total size, or how well-off each person is)."}, "coverage_note": "Captures effects on workers and output. The split of gains between labour and capital is only partly visible (low-skill wage findings); gains to employers are not separately scored.", "scored": false, "evidence_caveats": ["US-centric evidence \u2014 external validity to other destinations not established", "recency: NAS-2016 (2016) \u226510y old \u2014 refresh review"]}, {"id": "n_fiscal", "parent_id": "n_root", "evidence_quality": "well-evidenced", "label": "What is immigration's effect on host public finances?", "children": ["n_fiscal_highskill", "n_fiscal_lowskill", "n_fiscal_horizon"], "role": "dimension", "question": {"research": "What is immigration's effect on host public finances?", "simple": "Does immigration cost the government more than it brings in?"}, "depends_on": {"research": "Depends on immigrant skill/education, the public-goods accounting assumption (average vs marginal cost), and the time horizon (static snapshot vs lifetime-with-descendants).", "simple": "Depends on immigrants' education, how you count shared costs, and how far ahead you look (a snapshot now, or a lifetime including their children)."}, "scored": false, "evidence_caveats": ["mostly correlational \u2014 causal interpretation is not licensed", "recency: NAS-2016 (2016) \u226510y old \u2014 refresh review"]}, {"id": "n_innov", "parent_id": "n_root", "evidence_quality": "well-evidenced", "label": "How does immigration affect innovation and long-run productivity?", "children": ["n_innov_share", "n_innov_complement"], "role": "dimension", "question": {"research": "How does immigration affect innovation and long-run productivity?", "simple": "Does immigration help new ideas, inventions, and businesses?"}, "depends_on": {"research": "Depends on whether you mean immigrants' OWN output (share of patents/startups) or their EFFECT on native innovators (complement vs crowd-out).", "simple": "Depends on whether you mean immigrants' own inventions and firms, or their effect on local inventors."}, "scored": false, "evidence_caveats": []}, {"id": "n_social", "parent_id": "n_root", "evidence_quality": "thin", "label": "How does immigration affect public safety and social cohesion?", "children": ["n_social_crime", "n_social_trust", "n_social_integration"], "role": "dimension", "question": {"research": "How does immigration affect public safety and social cohesion?", "simple": "Does immigration affect crime and how well people get along?"}, "depends_on": {"research": "Splits into outcomes with very different evidence quality: crime (well-studied), social trust/cohesion (contested, thin), and long-run integration (generational).", "simple": "Splits into things with very different evidence: crime (well studied), trust (argued over, thin), and fitting in (slow, over generations)."}, "scored": false, "evidence_caveats": ["US-centric evidence \u2014 external validity to other destinations not established", "recency: NAS-2016 (2016) \u226510y old \u2014 refresh review"]}, {"id": "n_econ_wages_overall", "parent_id": "n_econ", "evidence_quality": "well-evidenced", "label": "Does immigration lower wages or employment for native-born workers overall?", "children": [], "role": "leaf", "question": {"research": "Does immigration lower wages or employment for native-born workers overall?", "simple": "Does immigration lower pay or cost jobs for workers already here?"}, "claim_evaluated": {"research": "Immigration lowers wages/employment for native-born workers overall.", "simple": "Immigration lowers pay or costs jobs for workers already in the country."}, "depends_on": null, "scored": true, "evidence_caveats": ["US-centric evidence \u2014 external validity to other destinations not established", "Geographic: OECD-ILO adds ten LMIC destinations (F-geo-1) where the native labour-market impact is negligible. Evidence base is US/OECD-heavy; external validity to other settings is partially addressed but remains uncertain.", "recency: NAS-2016 (2016) \u226510y old \u2014 refresh review", "recency: Borjas-2016 (2016) \u226510y old \u2014 refresh review"]}, {"id": "n_econ_wages_lowskill", "parent_id": "n_econ", "evidence_quality": "well-evidenced", "label": "Does immigration lower wages or employment for low-skilled natives and prior immigrants?", "children": [], "role": "leaf", "question": {"research": "Does immigration lower wages or employment for low-skilled natives and prior immigrants?", "simple": "Does immigration hurt pay for lower-paid workers and earlier immigrants?"}, "claim_evaluated": {"research": "Immigration lowers wages/employment for low-skilled natives and prior immigrants.", "simple": "Immigration lowers pay or costs jobs for lower-paid workers and earlier immigrants."}, "depends_on": null, "scored": true, "evidence_caveats": ["US-centric evidence \u2014 external validity to other destinations not established", "No LMIC low-skill-specific wage study located beyond the OECD-ILO aggregate. Evidence base is US-heavy; external validity to other settings is uncertain.", "single-source-heavy: NAS-2016 supplies 3/4 findings here", "recency: NAS-2016 (2016) \u226510y old \u2014 refresh review", "recency: CIS-2016 (2016) \u226510y old \u2014 refresh review"]}, {"id": "n_econ_gdp_pc", "parent_id": "n_econ", "evidence_quality": "well-evidenced", "label": "Does immigration raise GDP per capita (not just total GDP)?", "children": [], "role": "leaf", "question": {"research": "Does immigration raise GDP per capita (not just total GDP)?", "simple": "Does immigration make people better off on average, not just grow the economy?"}, "claim_evaluated": {"research": "Immigration raises GDP per capita, not merely aggregate GDP.", "simple": "Immigration makes the country richer per person, not just bigger overall."}, "depends_on": null, "scored": true, "evidence_caveats": ["Geographic: OECD-ILO (F-geo-2) extends the GDP-per-capita result to ten LMIC destinations ('immigration is unlikely to depress GDP per capita'). Evidence base is OECD-heavy; external validity to other settings is partially addressed but uncertain.", "single-source-heavy: OECD-migration supplies 3/4 findings here"]}, {"id": "n_fiscal_highskill", "parent_id": "n_fiscal", "evidence_quality": "well-evidenced", "label": "Are high-skilled immigrants net fiscal contributors?", "children": [], "role": "leaf", "question": {"research": "Are high-skilled immigrants net fiscal contributors?", "simple": "Do higher-earning immigrants pay in more than they take out?"}, "claim_evaluated": {"research": "High-skilled immigrants are net fiscal contributors.", "simple": "Higher-skilled immigrants pay more in taxes than they use in services."}, "depends_on": null, "scored": true, "evidence_caveats": ["US-centric evidence \u2014 external validity to other destinations not established", "No LMIC high-skill fiscal study located. Evidence base is US-heavy; external validity to other settings is uncertain.", "no independent AGAINST located \u2014 one-sided"]}, {"id": "n_fiscal_lowskill", "parent_id": "n_fiscal", "evidence_quality": "thin", "label": "Are low-skilled immigrants a net fiscal drain?", "children": [], "role": "leaf", "question": {"research": "Are low-skilled immigrants a net fiscal drain?", "simple": "Do lower-earning immigrants cost more than they pay in?"}, "claim_evaluated": {"research": "Low-skilled immigrants are a net fiscal drain.", "simple": "Lower-skilled immigrants cost the government more than they pay in taxes."}, "depends_on": null, "scored": true, "evidence_caveats": ["US-centric evidence \u2014 external validity to other destinations not established", "Geographic: OECD-ILO (F-geo-3) finds small/mixed fiscal impact across ten LMIC destinations (net positive in most; small deficit in Kyrgyzstan/Nepal), not a clear drain. Evidence base is US-heavy; external validity to other settings is partially addressed but uncertain.", "recency: NAS-2016 (2016) \u226510y old \u2014 refresh review"]}, {"id": "n_fiscal_horizon", "parent_id": "n_fiscal", "evidence_quality": "thin", "label": "Does the fiscal picture turn positive once you count descendants and the long run?", "children": [], "role": "leaf", "question": {"research": "Does the fiscal picture turn positive once you count descendants and the long run?", "simple": "Does it pay off over time, once you count immigrants' children?"}, "claim_evaluated": {"research": "Counting descendants and the long run, immigration is fiscally positive.", "simple": "Over the long run, counting immigrants' children, immigration pays off for the public purse."}, "depends_on": null, "scored": true, "evidence_caveats": ["US-centric evidence \u2014 external validity to other destinations not established", "No LMIC dynamic-scoring (descendants/long-run) study located. Evidence base is US-heavy; external validity to other settings is uncertain.", "single-source-heavy: NAS-2016 supplies 2/3 findings here", "recency: NAS-2016 (2016) \u226510y old \u2014 refresh review", "recency: Borjas-2016 (2016) \u226510y old \u2014 refresh review"]}, {"id": "n_innov_share", "parent_id": "n_innov", "evidence_quality": "well-evidenced", "label": "Do immigrants contribute disproportionately to patents and entrepreneurship?", "children": [], "role": "leaf", "question": {"research": "Do immigrants contribute disproportionately to patents and entrepreneurship?", "simple": "Do immigrants invent and start businesses more than their numbers?"}, "claim_evaluated": {"research": "Immigrants contribute disproportionately to patents and entrepreneurship.", "simple": "Immigrants invent things and start businesses at a higher rate than their share of the population."}, "depends_on": null, "scored": true, "evidence_caveats": ["US-centric evidence \u2014 external validity to other destinations not established", "mostly correlational \u2014 causal interpretation is not licensed", "No LMIC immigrant-innovation study located. External validity to other settings is uncertain.", "no independent AGAINST located \u2014 one-sided"]}, {"id": "n_innov_complement", "parent_id": "n_innov", "evidence_quality": "well-evidenced", "label": "Do high-skilled immigrants complement (rather than crowd out) native innovators?", "children": [], "role": "leaf", "question": {"research": "Do high-skilled immigrants complement (rather than crowd out) native innovators?", "simple": "Do skilled immigrants help or take opportunities from local inventors?"}, "claim_evaluated": {"research": "High-skilled immigrants complement rather than crowd out native innovators.", "simple": "Skilled immigrants help local inventors rather than taking their spots."}, "depends_on": null, "scored": true, "evidence_caveats": ["US-centric evidence \u2014 external validity to other destinations not established", "mostly correlational \u2014 causal interpretation is not licensed", "No LMIC study located. External validity to other settings is uncertain.", "recency: Hunt-2010 (2010) \u226510y old \u2014 refresh review", "recency: NAS-2016 (2016) \u226510y old \u2014 refresh review"]}, {"id": "n_social_crime", "parent_id": "n_social", "evidence_quality": "well-evidenced", "label": "Does immigration increase crime?", "children": [], "role": "leaf", "question": {"research": "Does immigration increase crime?", "simple": "Does immigration raise crime?"}, "claim_evaluated": {"research": "Immigration increases crime.", "simple": "Immigration raises crime."}, "depends_on": null, "scored": true, "evidence_caveats": ["mostly correlational \u2014 causal interpretation is not licensed", "Evidence base is US/European-heavy; Global-South immigration-crime evidence is largely qualitative or forced-displacement-focused. External validity to other settings is uncertain."]}, {"id": "n_social_trust", "parent_id": "n_social", "evidence_quality": "thin", "label": "Does immigration / ethnic diversity erode social trust and cohesion?", "children": [], "role": "leaf", "question": {"research": "Does immigration / ethnic diversity erode social trust and cohesion?", "simple": "Does more diversity make people trust each other less?"}, "claim_evaluated": {"research": "Immigration / ethnic diversity erodes social trust and cohesion.", "simple": "More immigration and diversity make people trust each other less."}, "depends_on": {"research": "LEAF: research runs thin here. Effect sizes small, method- and context-dependent, confounded by segregation. Belief from here rests on values (weight on local neighbour-trust vs national generalised trust).", "simple": "The research runs thin here. Effects are small, differ by place, and get tangled with segregation. From here it rests on your values \u2014 how much you weight local trust versus trust across the whole country."}, "scored": true, "evidence_caveats": ["mostly correlational \u2014 causal interpretation is not licensed", "Evidence base is European/US-heavy; social trust in Global-South settings is largely unexamined. External validity to other settings is uncertain.", "recency: Putnam-2007 (2007) \u226510y old \u2014 refresh review"]}, {"id": "n_social_integration", "parent_id": "n_social", "evidence_quality": "thin", "label": "Do immigrants and their descendants integrate over generations?", "children": [], "role": "leaf", "question": {"research": "Do immigrants and their descendants integrate over generations?", "simple": "Do immigrants and their kids fit in over time?"}, "claim_evaluated": {"research": "Immigrants and their descendants integrate over generations.", "simple": "Immigrants and their children settle in and get on over the generations."}, "depends_on": null, "scored": true, "evidence_caveats": ["US-centric evidence \u2014 external validity to other destinations not established", "mostly correlational \u2014 causal interpretation is not licensed", "single-source-heavy: NAS-2016 supplies 2/3 findings here", "recency: NAS-2016 (2016) \u226510y old \u2014 refresh review"]}], "findings": [{"finding_id": "F-root-1", "node_id": "n_root", "direction": "COMPLICATES", "claim_paragraph": {"research": "The literature never measures 'immigration good or bad?' directly. It measures distinct dimensions \u2014 labour market, public finances, innovation, social outcomes \u2014 each with its own data, methods and degree of consensus. The honest first move is to pick a dimension; the overall verdict is a weighted sum whose weights are a value choice, not a finding.", "simple": "No study measures 'is immigration good or bad' all at once. Researchers look at separate areas \u2014 jobs, government money, new ideas, and how people get along \u2014 and each has its own evidence. Pick an area first. Adding it all into one answer means deciding how much each area matters to you, which is a personal choice, not a fact."}, "effect_size": {"research": "qualitative", "simple": "qualitative"}, "source_type": "systematic-review", "source_citation": "National Academies of Sciences 2016, The Economic and Fiscal Consequences of Immigration; OECD, Economic impact of migration.", "triggers_split_to": ["n_econ", "n_fiscal", "n_innov", "n_social"], "tension_with": [], "source_strength": "strong", "evidence_type": "review", "source_cluster": "OECD-migration", "caveat": {"research": "Synthesis across many studies of varying design and quality.", "simple": "A round-up of many studies of mixed quality."}}, {"finding_id": "F-root-2", "node_id": "n_root", "direction": "COMPLICATES", "claim_paragraph": {"research": "Evidence is unevenly distributed. Economic and fiscal effects are heavily quantified (decades of meta-analyses); cultural cohesion and social trust are hard to operationalise and the evidence is thinner and more contested. A confident 'net positive' on the measurable dimensions does not transfer to the unmeasured ones.", "simple": "We know much more about some effects than others. The money side (jobs, taxes) has been studied for decades. Things like trust and culture are much harder to measure, so the evidence is thinner and people argue about it more. Being sure about the money side doesn't mean you can be sure about the rest."}, "effect_size": {"research": "qualitative", "simple": "qualitative"}, "source_type": "systematic-review", "source_citation": "NAS 2016 (summary); Dinesen, Schaeffer & S\u00f8nderskov 2020, Annual Review of Political Science.", "triggers_split_to": ["n_econ", "n_fiscal", "n_innov", "n_social"], "tension_with": [], "source_strength": "strong", "evidence_type": "review", "source_cluster": "NAS-2016", "caveat": {"research": "Synthesis across many studies of varying design and quality.", "simple": "A round-up of many studies of mixed quality."}}, {"finding_id": "F-econ-1", "node_id": "n_econ", "direction": "SUPPORTS", "claim_paragraph": {"research": "Across high-income destinations the overall labour-market effect on native-born workers is small. NAS 2016 concludes that, measured over 10+ years, the impact on the wages of native-born workers overall is very small, with little evidence of significant effects on overall native employment.", "simple": "For workers already in the country as a whole, immigration's effect on pay is small. A major US expert review found that, over ten years or more, the effect on locals' wages is very small, and jobs overall aren't much affected."}, "effect_size": {"research": "\u22480 on overall native wages over a 10-yr horizon", "simple": "almost no change to most locals' pay over 10+ years"}, "source_type": "systematic-review", "source_citation": "NAS 2016 (summary).", "triggers_split_to": [], "tension_with": ["F-tr-2"], "source_strength": "strong", "evidence_type": "review", "source_cluster": "NAS-2016", "caveat": {"research": "Synthesis across many studies of varying design and quality.", "simple": "A round-up of many studies of mixed quality."}}, {"finding_id": "F-econ-2", "node_id": "n_econ", "direction": "COMPLICATES", "claim_paragraph": {"research": "'Net positive for the economy' fractures along three lines: which workers (all natives vs the low-skilled natives and prior immigrants who are closest substitutes) and which metric (aggregate GDP, which immigration mechanically raises, vs GDP per capita, which living standards track). The same dataset supports opposite headlines depending on the choice.", "simple": "'Good for the economy' splits into different questions: which workers you mean (everyone, or just the lower-paid who compete most with new arrivals), and which measure (the economy's total size, which naturally grows, versus how well-off each person is). The same numbers can back opposite headlines."}, "effect_size": {"research": "qualitative", "simple": "qualitative"}, "source_type": "systematic-review", "source_citation": "NAS 2016; Borjas 2016 critique.", "triggers_split_to": ["n_econ_wages_overall", "n_econ_wages_lowskill", "n_econ_gdp_pc"], "tension_with": [], "source_strength": "strong", "evidence_type": "review", "source_cluster": "NAS-2016", "caveat": {"research": "Synthesis across many studies of varying design and quality.", "simple": "A round-up of many studies of mixed quality."}}, {"finding_id": "F-econ-3", "node_id": "n_econ", "direction": "SUPPORTS", "claim_paragraph": {"research": "In OECD-style overlapping-generations models where migrants arrive as working-age adults, immigration raises GDP per capita: one extra migrant per 1,000 inhabitants lifts GDP per capita ~0.25% in the shock year, peaking ~0.31% a year later, with fiscal balance also improving.", "simple": "In standard economic models where immigrants arrive as working-age adults, immigration slightly raises how much the economy produces per person, and helps the government's budget a little."}, "effect_size": {"research": "+0.25\u20130.31% GDP/capita per +1/1000 migration shock", "simple": "a small rise in output per person"}, "source_type": "single-study", "source_citation": "d'Albis, Boubtane & Coulibaly 2019, Immigration and public finances in OECD countries, J. Econ. Dynamics & Control.", "triggers_split_to": [], "tension_with": ["F-wl-2"], "source_strength": "moderate", "evidence_type": "model-based", "source_cluster": "OECD-migration", "caveat": {"research": "Sign and size depend on accounting/model assumptions stated in the source; different assumptions can flip the result.", "simple": "The answer leans on the assumptions in the calculation; change those and it can flip."}}, {"finding_id": "F-wo-1", "node_id": "n_econ_wages_overall", "direction": "CHALLENGES", "claim_paragraph": {"research": "The 'closest substitutes' logic predicts new immigrants compete most with similar prior immigrants, not with most natives. NAS 2016 finds the clearest negative wage/employment effects fall on prior immigrants \u2014 consistent with immigrants and natives being complements across most of the skill distribution.", "simple": "New immigrants compete most with earlier immigrants who have similar skills \u2014 not with most locals. The US review found the clearest downward pay pressure lands on earlier immigrants, suggesting immigrants and locals mostly fill different roles."}, "effect_size": {"research": "\u22480 for most natives; concentrated on prior immigrants", "simple": "little effect on most locals; earlier immigrants feel it most"}, "source_type": "systematic-review", "source_citation": "NAS 2016.", "triggers_split_to": [], "tension_with": ["F-wl-1"], "source_strength": "strong", "evidence_type": "review", "source_cluster": "NAS-2016", "caveat": {"research": "Synthesis across many studies of varying design and quality.", "simple": "A round-up of many studies of mixed quality."}}, {"finding_id": "F-wo-2", "node_id": "n_econ_wages_overall", "direction": "SUPPORTS", "claim_paragraph": {"research": "The 'small' headline is partly a modelling artifact. Borjas argues the near-zero long-run average wage effect follows from a mathematical assumption used to build the model rather than from the data, and that direct estimates can show larger distributional effects.", "simple": "One expert (Borjas) argues the 'small effect' partly comes from a built-in assumption in the model, not from the raw data, and that the real effect on some groups may be bigger."}, "effect_size": {"research": "qualitative", "simple": "qualitative"}, "source_type": "single-study", "source_citation": "Borjas 2016, A User's Guide to the 2016 National Academy Report.", "triggers_split_to": [], "tension_with": [], "source_strength": "moderate", "evidence_type": "theoretical", "source_cluster": "Borjas-2016", "caveat": {"research": "An argument or interpretation, not a direct measurement.", "simple": "This is an argument, not a direct measurement."}}, {"finding_id": "F-wo-3", "node_id": "n_econ_wages_overall", "direction": "COMPLICATES", "claim_paragraph": {"research": "Time horizon flips the short-run story: with capital fixed, short-run wage effects can be negative; over 10+ years capital adjusts and the average effect converges toward zero. Which number is 'true' depends on the horizon the reader cares about.", "simple": "Timing matters. Right after people arrive, pay can dip; but over ten years or more, businesses adjust and the effect fades toward zero. The 'right' answer depends on whether you care about the short or long term."}, "effect_size": {"research": "qualitative", "simple": "qualitative"}, "source_type": "systematic-review", "source_citation": "NAS 2016.", "triggers_split_to": [], "tension_with": [], "source_strength": "moderate", "evidence_type": "theoretical", "source_cluster": "NAS-2016", "caveat": {"research": "An argument or interpretation, not a direct measurement.", "simple": "This is an argument, not a direct measurement."}}, {"finding_id": "F-wl-1", "node_id": "n_econ_wages_lowskill", "direction": "SUPPORTS", "claim_paragraph": {"research": "For the most exposed group the effect is not zero. NAS 2016 states that, to the extent negative wage impacts occur, they fall on prior immigrants and native-born workers without a high-school diploma \u2014 the closest substitutes for low-skilled immigrant labour.", "simple": "For the workers most exposed, the effect isn't zero. The US review found that any pay drops land mainly on earlier immigrants and locals who didn't finish high school \u2014 the people whose jobs are most similar."}, "effect_size": {"research": "negative, concentrated on dropouts & prior immigrants", "simple": "some pay drop for the lowest-skilled and earlier immigrants"}, "source_type": "systematic-review", "source_citation": "NAS 2016.", "triggers_split_to": [], "tension_with": ["F-geo-1", "F-wo-1"], "source_strength": "strong", "evidence_type": "review", "source_cluster": "NAS-2016", "caveat": {"research": "Synthesis across many studies of varying design and quality.", "simple": "A round-up of many studies of mixed quality."}}, {"finding_id": "F-wl-2", "node_id": "n_econ_wages_lowskill", "direction": "SUPPORTS", "claim_paragraph": {"research": "An economic-theory reading of the same report (Center for Immigration Studies) computes that the aggregate 'immigration surplus' to natives is generated precisely by lowering wages of native workers \u2014 a redistribution from low-wage labour to employers, on the order of several percent for the most affected.", "simple": "One think-tank (which favours less immigration) argues that the economy's gain from immigration actually comes from paying some local workers less \u2014 money shifting from lower-paid workers to employers, by a few percent for those hit hardest."}, "effect_size": {"research": "~5% native wage cut in CIS's theoretical scenario", "simple": "a few percent lower pay for the hardest-hit (their estimate)"}, "source_type": "single-study", "source_citation": "Center for Immigration Studies 2016, analysis of the NAS report.", "triggers_split_to": [], "tension_with": ["F-econ-3"], "source_strength": "thin", "evidence_type": "theoretical", "source_cluster": "CIS-2016", "caveat": {"research": "An argument or interpretation, not a direct measurement. Source is an advocacy/think-tank organisation with a known prior; weigh the framing accordingly.", "simple": "This is an argument, not a direct measurement. The source is a campaign group with a known view \u2014 read the spin with care."}}, {"finding_id": "F-wl-3", "node_id": "n_econ_wages_lowskill", "direction": "CHALLENGES", "claim_paragraph": {"research": "Quasi-experimental studies of sudden low-skill inflows (the Mariel boatlift literature) remain genuinely unsettled: depending on specification and comparison group, estimated effects on low-skilled native wages range from near-zero to modestly negative. The dispersion itself is the finding.", "simple": "Studies of sudden large arrivals of lower-skilled workers still disagree: depending on how you crunch the numbers, the effect on local pay ranges from none to slightly negative. That disagreement is itself the honest answer."}, "effect_size": {"research": "range: \u22480 to modestly negative", "simple": "somewhere between no effect and slightly negative"}, "source_type": "single-study", "source_citation": "NAS 2016 summary of the Card\u2013Borjas Mariel debate.", "triggers_split_to": [], "tension_with": [], "source_strength": "thin", "evidence_type": "quasi-experimental", "source_cluster": "NAS-2016", "caveat": {"research": "Uses a natural-experiment / identification strategy \u2014 stronger on causation but narrow in setting.", "simple": "Uses a real-world 'natural experiment,' so it's better at showing cause \u2014 but only for that setting."}}, {"finding_id": "F-wl-4", "node_id": "n_econ_wages_lowskill", "direction": "COMPLICATES", "claim_paragraph": {"research": "'Low-skilled natives' hides heterogeneity: NAS finds reduced hours (not employment) for teens; separate effects for dropouts and for prior immigrants. Aggregating them obscures that the burden is narrow and specific, not economy-wide.", "simple": "'Lower-skilled locals' isn't one group. Teenagers, people without a diploma, and earlier immigrants are each affected differently. Lumping them together hides that the impact is narrow and specific, not spread across the whole economy."}, "effect_size": {"research": "qualitative", "simple": "qualitative"}, "source_type": "systematic-review", "source_citation": "NAS 2016.", "triggers_split_to": [], "tension_with": [], "source_strength": "moderate", "evidence_type": "observational", "source_cluster": "NAS-2016", "caveat": {"research": "Correlational; selection and confounding (where immigrants settle, who is selected to migrate) are not fully ruled out.", "simple": "This is a pattern, not proof of cause \u2014 things like where immigrants settle, or who chooses to move, could be behind it."}}, {"finding_id": "F-gp-1", "node_id": "n_econ_gdp_pc", "direction": "SUPPORTS", "claim_paragraph": {"research": "Immigration unambiguously raises aggregate GDP (more workers, more output). The harder per-capita claim is supported in OECD work: the joint ILO\u2013OECD review concludes immigration is unlikely to depress GDP per capita across studied destinations.", "simple": "Immigration clearly makes the economy bigger. The harder question \u2014 better off per person \u2014 leans positive too: a major international review found immigration is unlikely to lower how well-off people are on average."}, "effect_size": {"research": "per-capita: non-negative on average", "simple": "on average, no drop in living standards per person"}, "source_type": "systematic-review", "source_citation": "OECD/ILO 2018, How Immigrants Contribute.", "triggers_split_to": [], "tension_with": ["F-geo-2"], "source_strength": "moderate", "evidence_type": "review", "source_cluster": "OECD-migration", "caveat": {"research": "Synthesis across many studies of varying design and quality.", "simple": "A round-up of many studies of mixed quality."}}, {"finding_id": "F-gp-2", "node_id": "n_econ_gdp_pc", "direction": "CHALLENGES", "claim_paragraph": {"research": "Aggregate-GDP gains can be near-irrelevant to natives: if output and population rise together, GDP per capita and native living standards may barely move. OECD finds the overall growth impact is often negligible and highly contextual, not a reliable per-capita boost.", "simple": "A bigger economy can mean little for locals: if both the economy and the population grow together, the amount per person barely moves. The same review found the overall effect on growth is often tiny and depends heavily on the situation."}, "effect_size": {"research": "growth impact often 'negligible'", "simple": "often too small to matter"}, "source_type": "systematic-review", "source_citation": "OECD/ILO 2018.", "triggers_split_to": [], "tension_with": [], "source_strength": "moderate", "evidence_type": "review", "source_cluster": "OECD-migration", "caveat": {"research": "Synthesis across many studies of varying design and quality.", "simple": "A round-up of many studies of mixed quality."}}, {"finding_id": "F-gp-3", "node_id": "n_econ_gdp_pc", "direction": "COMPLICATES", "claim_paragraph": {"research": "The per-capita effect depends on immigrant composition (working-age vs dependents, skill level) and on productivity channels OECD finds 'less clear.' Demography drives the modelled gains; change the age/skill mix and the per-capita result moves.", "simple": "Whether people end up better off per person depends on who arrives (working-age or dependents, higher- or lower-skilled) and how they affect productivity \u2014 which is less clear. Change the mix of arrivals and the answer changes."}, "effect_size": {"research": "qualitative", "simple": "qualitative"}, "source_type": "systematic-review", "source_citation": "OECD/ILO 2018; d'Albis et al. 2019.", "triggers_split_to": [], "tension_with": [], "source_strength": "moderate", "evidence_type": "review", "source_cluster": "OECD-migration", "caveat": {"research": "Synthesis across many studies of varying design and quality.", "simple": "A round-up of many studies of mixed quality."}}, {"finding_id": "F-fis-1", "node_id": "n_fiscal", "direction": "COMPLICATES", "claim_paragraph": {"research": "There is no single fiscal number. NAS 2016 produced eight scenarios whose sign depends on (a) whether immigrants are charged the average or marginal cost of pure public goods like defence, (b) immigrant education, and (c) the time horizon \u2014 yielding anything from a ~$43B to ~$299B annual burden, or a long-run surplus.", "simple": "There's no single answer on cost to government. The US review ran eight versions and the result flips depending on how you count shared costs like defence, immigrants' education levels, and how far into the future you look \u2014 anywhere from a yearly cost to a long-term gain."}, "effect_size": {"research": "range: ~$43B to ~$299B/yr, or long-run surplus", "simple": "a yearly cost or a long-term gain, depending on the method"}, "source_type": "systematic-review", "source_citation": "NAS 2016; Borjas 2016; Dallas Fed 2017.", "triggers_split_to": ["n_fiscal_highskill", "n_fiscal_lowskill", "n_fiscal_horizon"], "tension_with": [], "source_strength": "strong", "evidence_type": "model-based", "source_cluster": "NAS-2016", "caveat": {"research": "Sign and size depend on accounting/model assumptions stated in the source; different assumptions can flip the result.", "simple": "The answer leans on the assumptions in the calculation; change those and it can flip."}}, {"finding_id": "F-fis-2", "node_id": "n_fiscal", "direction": "SUPPORTS", "claim_paragraph": {"research": "In OECD cross-country accounting, immigrants are generally not heavier users of benefits than the native-born, and whether they are net contributors hinges mostly on labour-market integration (employment and wages) rather than on immigration itself.", "simple": "Across rich countries, immigrants generally don't use more benefits than locals. Whether they pay in more than they take out depends mostly on whether they have jobs and decent pay \u2014 not on immigration by itself."}, "effect_size": {"research": "qualitative", "simple": "qualitative"}, "source_type": "systematic-review", "source_citation": "OECD, Economic impact of migration.", "triggers_split_to": [], "tension_with": ["F-fl-1"], "source_strength": "moderate", "evidence_type": "observational", "source_cluster": "OECD-migration", "caveat": {"research": "Correlational; selection and confounding (where immigrants settle, who is selected to migrate) are not fully ruled out.", "simple": "This is a pattern, not proof of cause \u2014 things like where immigrants settle, or who chooses to move, could be behind it."}}, {"finding_id": "F-fh-1", "node_id": "n_fiscal_highskill", "direction": "SUPPORTS", "claim_paragraph": {"research": "Highly-educated immigrants are clear net fiscal contributors: the Dallas Fed's reading of NAS 2016 finds they contribute far more in taxes than they consume in benefits, and OECD finds per-capita net fiscal contribution rises with education level.", "simple": "Higher-educated immigrants clearly pay in more than they take out \u2014 a lot more in taxes than they use in services \u2014 and the better-educated the immigrant, the bigger the surplus."}, "effect_size": {"research": "large positive; revenue/benefit ratio well above 1", "simple": "clearly pay in more than they take out"}, "source_type": "systematic-review", "source_citation": "Dallas Fed 2017; OECD/ILO 2018.", "triggers_split_to": [], "tension_with": [], "source_strength": "strong", "evidence_type": "model-based", "source_cluster": "DallasFed-2017", "caveat": {"research": "Sign and size depend on accounting/model assumptions stated in the source; different assumptions can flip the result.", "simple": "The answer leans on the assumptions in the calculation; change those and it can flip."}}, {"finding_id": "F-fh-2", "node_id": "n_fiscal_highskill", "direction": "COMPLICATES", "claim_paragraph": {"research": "Even here the public-goods assumption bites: if high-skilled immigrants are assigned the average cost of pure public goods (defence, debt interest), their measured contribution shrinks. The positive result is robust but not assumption-free.", "simple": "Even here, how you count shared costs matters: charge them a full share of things like defence and the surplus shrinks. Still positive, but not regardless of the method."}, "effect_size": {"research": "qualitative", "simple": "qualitative"}, "source_type": "single-study", "source_citation": "Dallas Fed 2017.", "triggers_split_to": [], "tension_with": [], "source_strength": "moderate", "evidence_type": "model-based", "source_cluster": "DallasFed-2017", "caveat": {"research": "Sign and size depend on accounting/model assumptions stated in the source; different assumptions can flip the result.", "simple": "The answer leans on the assumptions in the calculation; change those and it can flip."}}, {"finding_id": "F-fl-1", "node_id": "n_fiscal_lowskill", "direction": "SUPPORTS", "claim_paragraph": {"research": "Under the average-cost public-goods assumption, NAS 2016 scenarios show immigrants (legal and illegal) as a present-day net drain, as large as ~$299B/yr, driven heavily by less-educated immigrants and the cost of educating their (native-born) children.", "simple": "Count shared costs one common way, and immigrants (including through their kids' schooling) look like a net cost to government \u2014 driven mainly by lower-educated arrivals."}, "effect_size": {"research": "up to ~$299B/yr aggregate drain (avg-cost)", "simple": "looks like a net cost under one common method"}, "source_type": "systematic-review", "source_citation": "NAS 2016; CIS 2016.", "triggers_split_to": [], "tension_with": ["F-fis-2", "F-fl-2", "F-geo-3"], "source_strength": "moderate", "evidence_type": "model-based", "source_cluster": "NAS-2016", "caveat": {"research": "Sign and size depend on accounting/model assumptions stated in the source; different assumptions can flip the result.", "simple": "The answer leans on the assumptions in the calculation; change those and it can flip."}}, {"finding_id": "F-fl-2", "node_id": "n_fiscal_lowskill", "direction": "CHALLENGES", "claim_paragraph": {"research": "Under the marginal-cost assumption (immigrants don't add to the cost of pure public goods), the Dallas Fed finds the long-run fiscal impact turns positive and the short-run negative effect is very small \u2014 less negative than that of comparable natives.", "simple": "Count shared costs another reasonable way (immigrants don't add to fixed costs like defence), and the long-term effect turns positive \u2014 and even the short-term cost is smaller than for similar locals."}, "effect_size": {"research": "long-run positive; short-run small-negative", "simple": "turns into a net gain under another method"}, "source_type": "single-study", "source_citation": "Dallas Fed 2017.", "triggers_split_to": [], "tension_with": ["F-fl-1"], "source_strength": "moderate", "evidence_type": "model-based", "source_cluster": "DallasFed-2017", "caveat": {"research": "Sign and size depend on accounting/model assumptions stated in the source; different assumptions can flip the result.", "simple": "The answer leans on the assumptions in the calculation; change those and it can flip."}}, {"finding_id": "F-fl-3", "node_id": "n_fiscal_lowskill", "direction": "COMPLICATES", "claim_paragraph": {"research": "The low-skill fiscal result is a welfare-state design question as much as an immigration question: generous transfers plus low earnings produce drains; the same immigrant in a thinner welfare state nets differently. Part of what is measured is the host's policy, not the migrant.", "simple": "This is as much about the country's benefit system as about immigrants: generous benefits plus low earnings create a cost; the same person in a leaner system nets out differently. You're partly measuring the country's own policies."}, "effect_size": {"research": "qualitative", "simple": "qualitative"}, "source_type": "single-study", "source_citation": "OECD, Economic impact of migration.", "triggers_split_to": [], "tension_with": [], "source_strength": "thin", "evidence_type": "theoretical", "source_cluster": "OECD-migration", "caveat": {"research": "An argument or interpretation, not a direct measurement.", "simple": "This is an argument, not a direct measurement."}}, {"finding_id": "F-fhz-1", "node_id": "n_fiscal_horizon", "direction": "SUPPORTS", "claim_paragraph": {"research": "Lengthening the horizon to include descendants improves the picture: NAS finds the children of immigrants (second generation) are among the strongest net fiscal contributors, often out-earning and out-paying comparable third-plus-generation natives.", "simple": "Look further ahead and it improves: the US review found immigrants' children are among the biggest net contributors \u2014 often earning and paying in more than long-settled locals."}, "effect_size": {"research": "second generation: strongly net positive", "simple": "immigrants' children pay in strongly"}, "source_type": "systematic-review", "source_citation": "NAS 2016.", "triggers_split_to": [], "tension_with": ["F-fhz-2"], "source_strength": "moderate", "evidence_type": "observational", "source_cluster": "NAS-2016", "caveat": {"research": "Correlational; selection and confounding (where immigrants settle, who is selected to migrate) are not fully ruled out.", "simple": "This is a pattern, not proof of cause \u2014 things like where immigrants settle, or who chooses to move, could be behind it."}}, {"finding_id": "F-fhz-2", "node_id": "n_fiscal_horizon", "direction": "CHALLENGES", "claim_paragraph": {"research": "75-year projections are fragile. Borjas argues the long-run estimates that net taxes and outlays over 75 years are 'easily manipulated' to produce large positive or negative numbers depending on assumptions about future budgets, earnings and fertility.", "simple": "75-year forecasts are shaky. Borjas argues these long-range numbers can be pushed to look very positive or very negative just by changing guesses about the future."}, "effect_size": {"research": "long-run estimate sign is assumption-driven", "simple": "the long-run number can be bent to any answer"}, "source_type": "single-study", "source_citation": "Borjas 2016.", "triggers_split_to": [], "tension_with": ["F-fhz-1"], "source_strength": "moderate", "evidence_type": "theoretical", "source_cluster": "Borjas-2016", "caveat": {"research": "An argument or interpretation, not a direct measurement.", "simple": "This is an argument, not a direct measurement."}}, {"finding_id": "F-fhz-3", "node_id": "n_fiscal_horizon", "direction": "COMPLICATES", "claim_paragraph": {"research": "The accounting unit changes who 'counts': charging immigrant parents for educating their US-born (native) children makes immigrants look costly up front but ignores those children's decades of later tax payments. Static snapshots and lifetime ledgers tell opposite stories.", "simple": "Who you count changes the story: billing immigrant parents for their US-born kids' schooling makes them look expensive now, but ignores the taxes those kids pay for decades. A snapshot and a lifetime tally point opposite ways."}, "effect_size": {"research": "qualitative", "simple": "qualitative"}, "source_type": "systematic-review", "source_citation": "NAS 2016 (Lee 2017 review).", "triggers_split_to": [], "tension_with": [], "source_strength": "moderate", "evidence_type": "model-based", "source_cluster": "NAS-2016", "caveat": {"research": "Sign and size depend on accounting/model assumptions stated in the source; different assumptions can flip the result.", "simple": "The answer leans on the assumptions in the calculation; change those and it can flip."}}, {"finding_id": "F-inn-1", "node_id": "n_innov", "direction": "COMPLICATES", "claim_paragraph": {"research": "Two different claims hide under 'immigrants drive innovation': their direct output (do immigrants themselves patent and found firms at high rates?) and their spillover (do they raise or lower native innovators' productivity?). The first is counting; the second is a causal effect on others.", "simple": "'Immigrants drive innovation' hides two different claims: that immigrants themselves invent and start firms a lot, and that they make local inventors more (or less) productive. The first is counting; the second is about their effect on others."}, "effect_size": {"research": "qualitative", "simple": "qualitative"}, "source_type": "systematic-review", "source_citation": "Krol 2021 review (SSRN/Mercatus).", "triggers_split_to": ["n_innov_share", "n_innov_complement"], "tension_with": [], "source_strength": "strong", "evidence_type": "review", "source_cluster": "Krol-2021", "caveat": {"research": "Synthesis across many studies of varying design and quality. Source is an advocacy/think-tank organisation with a known prior; weigh the framing accordingly.", "simple": "A round-up of many studies of mixed quality. The source is a campaign group with a known view \u2014 read the spin with care."}}, {"finding_id": "F-is-1", "node_id": "n_innov_share", "direction": "SUPPORTS", "claim_paragraph": {"research": "Immigrants are over-represented in measured innovation. Tracking ~880,000 US inventors (1990\u20132016), Bernstein, Diamond et al. find immigrants were 16% of inventors but produced 23% of patents; weighting by patent quality/value pushes the share higher.", "simple": "Immigrants invent more than their numbers suggest. Tracking about 880,000 US inventors, researchers found immigrants were 16% of inventors but produced 23% of patents \u2014 more once you weight by how valuable the patents are."}, "effect_size": {"research": "16% of inventors \u2192 23% of patents", "simple": "16% of inventors, but 23% of patents"}, "source_type": "single-study", "source_citation": "Bernstein, Diamond, McQuade & Pousada 2022 (SIEPR/NBER).", "triggers_split_to": [], "tension_with": ["F-ic-3"], "source_strength": "moderate", "evidence_type": "observational", "source_cluster": "Diamond-2022", "caveat": {"research": "Correlational; selection and confounding (where immigrants settle, who is selected to migrate) are not fully ruled out.", "simple": "This is a pattern, not proof of cause \u2014 things like where immigrants settle, or who chooses to move, could be behind it."}}, {"finding_id": "F-is-2", "node_id": "n_innov_share", "direction": "SUPPORTS", "claim_paragraph": {"research": "On entrepreneurship, the immigrant share of US founders rose to ~29% by 2020 (vs ~14\u201315% of population), exceeding 40% among VC-backed and leading AI firms; immigrant-owned firms generate more patents per worker.", "simple": "Immigrants start a lot of companies: about 29% of US founders by 2020 (versus roughly 15% of the population), and over 40% at top tech and AI firms. Immigrant-run firms also produce more patents per worker."}, "effect_size": {"research": "founder share ~29%; >40% in frontier tech", "simple": "about 29% of founders; over 40% in top tech"}, "source_type": "systematic-review", "source_citation": "Chodavadia, Kerr, Kerr & Maiden 2024 (NBER WP 32400).", "triggers_split_to": [], "tension_with": [], "source_strength": "strong", "evidence_type": "observational", "source_cluster": "Kerr-NBER-2024", "caveat": {"research": "Correlational; selection and confounding (where immigrants settle, who is selected to migrate) are not fully ruled out.", "simple": "This is a pattern, not proof of cause \u2014 things like where immigrants settle, or who chooses to move, could be behind it."}}, {"finding_id": "F-is-3", "node_id": "n_innov_share", "direction": "COMPLICATES", "claim_paragraph": {"research": "Most of the gap is composition, not magic: immigrants are concentrated in STEM and arrive selected for skills. NBER finds education and field-of-study explain part but not all of the higher innovation rate \u2014 so 'immigrants are more innovative' and 'policy selects innovative people' are hard to separate.", "simple": "Much of the gap is who immigrates, not something magical: immigrants cluster in science and tech and are picked for skills. Research finds their field and education explain part \u2014 but not all \u2014 of the higher rate. So it's hard to separate 'immigrants invent more' from 'we admit inventive people.'"}, "effect_size": {"research": "qualitative", "simple": "qualitative"}, "source_type": "systematic-review", "source_citation": "NBER 2024; Krol 2021.", "triggers_split_to": [], "tension_with": [], "source_strength": "moderate", "evidence_type": "observational", "source_cluster": "Krol-2021", "caveat": {"research": "Correlational; selection and confounding (where immigrants settle, who is selected to migrate) are not fully ruled out. Source is an advocacy/think-tank organisation with a known prior; weigh the framing accordingly.", "simple": "This is a pattern, not proof of cause \u2014 things like where immigrants settle, or who chooses to move, could be behind it. The source is a campaign group with a known view \u2014 read the spin with care."}}, {"finding_id": "F-ic-1", "node_id": "n_innov_complement", "direction": "SUPPORTS", "claim_paragraph": {"research": "Immigrant inventors appear to complement natives: Hunt & Gauthier-Loiselle estimate a 1-percentage-point rise in immigrant college graduates' population share raises patents per capita by 9\u201318% \u2014 more than the immigrants' own patents alone, implying positive spillovers onto native inventors.", "simple": "Immigrant inventors seem to help local ones. One study found that raising immigrant college graduates by 1% of the population lifted patents per person by 9\u201318% \u2014 more than the immigrants' own patents, so locals invent more too."}, "effect_size": {"research": "+9\u201318% patents/capita per +1pp immigrant grads", "simple": "patents per person rise 9\u201318%"}, "source_type": "single-study", "source_citation": "Hunt & Gauthier-Loiselle 2010, AEJ: Macroeconomics.", "triggers_split_to": [], "tension_with": [], "source_strength": "moderate", "evidence_type": "observational", "source_cluster": "Hunt-2010", "caveat": {"research": "Correlational; selection and confounding (where immigrants settle, who is selected to migrate) are not fully ruled out.", "simple": "This is a pattern, not proof of cause \u2014 things like where immigrants settle, or who chooses to move, could be behind it."}}, {"finding_id": "F-ic-2", "node_id": "n_innov_complement", "direction": "SUPPORTS", "claim_paragraph": {"research": "Mixed founding teams outperform: US startups with both native and immigrant founders file ~117% more patents than immigrant-only and ~28% more than native-only teams, via wider access to labour, capital and markets.", "simple": "Teams with both local and immigrant founders do better: US startups with mixed founders filed about 117% more patents than immigrant-only teams and about 28% more than local-only teams."}, "effect_size": {"research": "+117% vs immigrant-only; +28% vs native-only", "simple": "mixed teams file far more patents"}, "source_type": "single-study", "source_citation": "McQuade et al. 2026 (UC Berkeley Haas).", "triggers_split_to": [], "tension_with": [], "source_strength": "moderate", "evidence_type": "observational", "source_cluster": "McQuade-2026", "caveat": {"research": "Correlational; selection and confounding (where immigrants settle, who is selected to migrate) are not fully ruled out.", "simple": "This is a pattern, not proof of cause \u2014 things like where immigrants settle, or who chooses to move, could be behind it."}}, {"finding_id": "F-ic-3", "node_id": "n_innov_complement", "direction": "CHALLENGES", "claim_paragraph": {"research": "Crowd-out is plausible at the margin in fixed-slot systems (university places, H-1B caps, lab budgets): some studies find native students/workers diverted out of fields with large foreign inflows \u2014 though evidence of NET displacement of native innovators is weaker than the complementarity evidence.", "simple": "Crowding-out is possible where slots are fixed (university places, visas, lab budgets): some studies find locals shifting away from fields flooded with newcomers. But the evidence that locals are actually pushed out overall is weaker than the evidence that immigrants help."}, "effect_size": {"research": "marginal diversion; weak net-displacement evidence", "simple": "some shifting; weak evidence locals are pushed out"}, "source_type": "single-study", "source_citation": "NAS 2016 (skilled-immigration section).", "triggers_split_to": [], "tension_with": ["F-is-1"], "source_strength": "thin", "evidence_type": "observational", "source_cluster": "NAS-2016", "caveat": {"research": "Correlational; selection and confounding (where immigrants settle, who is selected to migrate) are not fully ruled out.", "simple": "This is a pattern, not proof of cause \u2014 things like where immigrants settle, or who chooses to move, could be behind it."}}, {"finding_id": "F-soc-1", "node_id": "n_social", "direction": "COMPLICATES", "claim_paragraph": {"research": "'Social impact' splits into outcomes with wildly different evidence quality: crime (heavily studied, fairly clear), social trust/cohesion (contested, small and method-dependent effects), and long-run integration (slow, generational). Treating them as one verdict is where most public arguments go wrong.", "simple": "'Social effects' covers very different things: crime (well studied, fairly clear), trust between people (argued over, small effects), and fitting in over generations (slow). Rolling them into one verdict is where most arguments go wrong."}, "effect_size": {"research": "qualitative", "simple": "qualitative"}, "source_type": "systematic-review", "source_citation": "NAS 2016; Dinesen et al. 2020.", "triggers_split_to": ["n_social_crime", "n_social_trust", "n_social_integration"], "tension_with": [], "source_strength": "strong", "evidence_type": "review", "source_cluster": "NAS-2016", "caveat": {"research": "Synthesis across many studies of varying design and quality.", "simple": "A round-up of many studies of mixed quality."}}, {"finding_id": "F-cr-1", "node_id": "n_social_crime", "direction": "CHALLENGES", "claim_paragraph": {"research": "In the US the immigration\u2013crime association is weak and not positive. A meta-analysis of 51 studies (1994\u20132014) finds the cross-sectional association is essentially zero AND the longitudinal association (from the stronger designs) is small and negative, mean r \u2248 \u22120.15. Both are reported: the honest summary is 'no positive link', not a strong protective effect (r \u2248 \u22120.15 explains ~2% of variance).", "simple": "In the US, more immigration doesn't mean more crime. A review of 51 studies found basically no link, and the stronger studies found a small drop in crime where immigration rose. 'Small drop' \u2014 not a big protective effect."}, "effect_size": {"research": "cross-sectional r\u22480; longitudinal r\u2248\u22120.15 (weak, ~2% variance)", "simple": "no link, or a small drop in crime"}, "source_type": "meta-analysis", "source_citation": "Ousey & Kubrin 2018, Annual Review of Criminology.", "triggers_split_to": [], "tension_with": [], "source_strength": "strong", "evidence_type": "observational", "source_cluster": "OuseyKubrin-2018", "caveat": {"research": "Correlational; selection and confounding (where immigrants settle, who is selected to migrate) are not fully ruled out.", "simple": "This is a pattern, not proof of cause \u2014 things like where immigrants settle, or who chooses to move, could be behind it."}}, {"finding_id": "F-cr-2", "node_id": "n_social_crime", "direction": "CHALLENGES", "claim_paragraph": {"research": "Individual-level US data agree: immigrants have had lower incarceration rates than the native-born since at least 1870, and in 2020 were ~60% less likely to be incarcerated.", "simple": "US records agree: immigrants have been locked up less often than people born there since at least 1870, and in 2020 were about 60% less likely to be in prison."}, "effect_size": {"research": "~60% lower incarceration odds (2020); pattern holds since 1870", "simple": "about 60% less likely to be imprisoned"}, "source_type": "single-study", "source_citation": "Abramitzky et al. (NBER), via Migration Policy Institute 2025.", "triggers_split_to": [], "tension_with": ["F-cr-4"], "source_strength": "strong", "evidence_type": "observational", "source_cluster": "Abramitzky-NBER", "caveat": {"research": "Correlational; selection and confounding (where immigrants settle, who is selected to migrate) are not fully ruled out. Single study, but population-level administrative data across many decades, hence high strength.", "simple": "This is a pattern, not proof of cause \u2014 things like where immigrants settle, or who chooses to move, could be behind it. Just one study, but it uses full government records over many years, so it counts as strong."}}, {"finding_id": "F-cr-3", "node_id": "n_social_crime", "direction": "COMPLICATES", "claim_paragraph": {"research": "The result is geographically bounded. Comparative reviews find the US/Canada/Australia pattern (null-or-negative) does not cleanly transfer to Europe, where findings are 'more mixed' \u2014 so 'immigrants commit less crime' is a claim about specific contexts, not a universal law.", "simple": "It depends on where. The 'less crime' pattern in the US, Canada and Australia doesn't clearly hold in Europe, where results are more mixed. So it's not a universal rule."}, "effect_size": {"research": "qualitative; US\u2248neg, Europe mixed", "simple": "US lower; Europe mixed"}, "source_type": "systematic-review", "source_citation": "Crime and Justice 2025, comparative review.", "triggers_split_to": [], "tension_with": [], "source_strength": "moderate", "evidence_type": "review", "source_cluster": "CrimeJustice-2025", "caveat": {"research": "Synthesis across many studies of varying design and quality.", "simple": "A round-up of many studies of mixed quality."}}, {"finding_id": "F-tr-1", "node_id": "n_social_trust", "direction": "SUPPORTS", "claim_paragraph": {"research": "Putnam's 'constrict' finding: in the short-to-medium run, more ethnically diverse US neighbourhoods show lower social trust \u2014 including trust of one's own group \u2014 plus less altruism and fewer friendships ('hunkering down'). The strongest single source for diversity harming cohesion.", "simple": "Putnam's famous finding: in the short term, more mixed US neighbourhoods showed less trust \u2014 even of one's own group \u2014 plus less helping and fewer friendships ('hunkering down'). It's the strongest single case that diversity can hurt community."}, "effect_size": {"research": "short-run: lower neighbourhood trust", "simple": "less neighbourhood trust in the short term"}, "source_type": "single-study", "source_citation": "Putnam 2007, E Pluribus Unum, Scandinavian Political Studies.", "triggers_split_to": [], "tension_with": ["F-tr-3"], "source_strength": "moderate", "evidence_type": "observational", "source_cluster": "Putnam-2007", "caveat": {"research": "Correlational; selection and confounding (where immigrants settle, who is selected to migrate) are not fully ruled out.", "simple": "This is a pattern, not proof of cause \u2014 things like where immigrants settle, or who chooses to move, could be behind it."}}, {"finding_id": "F-tr-2", "node_id": "n_social_trust", "direction": "SUPPORTS", "claim_paragraph": {"research": "The pattern partly survives meta-analysis: Dinesen, Schaeffer & S\u00f8nderskov (1,001 estimates, 87 studies) find a statistically significant negative diversity\u2013trust relationship overall \u2014 but small, and concentrated in trust in neighbours and at local geographic scales.", "simple": "A big review (1,001 results from 87 studies) found a real but small link between diversity and lower trust \u2014 mostly about trusting your immediate neighbours, and mostly at the local level."}, "effect_size": {"research": "significant but small; strongest for neighbour trust", "simple": "real but small; mainly local, neighbour trust"}, "source_type": "meta-analysis", "source_citation": "Dinesen, Schaeffer & S\u00f8nderskov 2020, Annual Review of Political Science.", "triggers_split_to": [], "tension_with": ["F-econ-1"], "source_strength": "strong", "evidence_type": "observational", "source_cluster": "Dinesen-2020", "caveat": {"research": "Correlational; selection and confounding (where immigrants settle, who is selected to migrate) are not fully ruled out.", "simple": "This is a pattern, not proof of cause \u2014 things like where immigrants settle, or who chooses to move, could be behind it."}}, {"finding_id": "F-tr-3", "node_id": "n_social_trust", "direction": "CHALLENGES", "claim_paragraph": {"research": "The effect largely evaporates for generalised trust and at national scale, and may track segregation rather than diversity itself: in integrated (vs segregated) neighbourhoods the negative association weakens \u2014 pointing to policy (housing, contact) rather than diversity per se as the lever.", "simple": "The link mostly disappears for general trust and across whole countries, and may be about neighbourhoods being split up rather than diverse: where people actually mix, the effect fades. That points to housing and contact \u2014 not diversity itself \u2014 as the lever."}, "effect_size": {"research": "\u22480 for generalised/national trust", "simple": "little to no effect on general, countrywide trust"}, "source_type": "single-study", "source_citation": "Dinesen et al. 2020, Annual Review of Political Science (moderators of the Uslaner 2012 diversity-distrust argument).", "triggers_split_to": [], "tension_with": ["F-tr-1"], "source_strength": "moderate", "evidence_type": "observational", "source_cluster": "Dinesen-2020", "caveat": {"research": "Correlational; selection and confounding (where immigrants settle, who is selected to migrate) are not fully ruled out.", "simple": "This is a pattern, not proof of cause \u2014 things like where immigrants settle, or who chooses to move, could be behind it."}}, {"finding_id": "F-tr-4", "node_id": "n_social_trust", "direction": "CHALLENGES", "claim_paragraph": {"research": "Putnam himself frames the constrict effect as short-run: he argues successful immigrant societies historically rebuild cohesion through new cross-cutting identities, so long-run effects on solidarity may be neutral-to-positive. The sign depends on the time horizon.", "simple": "Putnam says the trust dip is short-term: over the long run, societies tend to rebuild a shared identity, so the lasting effect may be neutral or even positive. It depends on the time frame."}, "effect_size": {"research": "long-run: neutral-to-positive (claimed)", "simple": "may fade or reverse over the long run"}, "source_type": "single-study", "source_citation": "Putnam 2007.", "triggers_split_to": [], "tension_with": [], "source_strength": "thin", "evidence_type": "theoretical", "source_cluster": "Putnam-2007", "caveat": {"research": "An argument or interpretation, not a direct measurement.", "simple": "This is an argument, not a direct measurement."}}, {"finding_id": "F-tr-5", "node_id": "n_social_trust", "direction": "COMPLICATES", "claim_paragraph": {"research": "This is where the research runs out. Effect sizes are small, method- and context-dependent, confounded by segregation and deprivation, and concentrated on the hardest-to-define outcome ('cohesion'). Beyond here, belief rests on how much weight you place on local neighbour-trust vs national generalised trust \u2014 a values question.", "simple": "This is where solid evidence runs out. The effects are small, differ by place and method, get tangled up with segregation and poverty, and hang on the fuzziest thing to measure ('community'). From here, it comes down to how much you weight local neighbour-trust versus trust across the whole country \u2014 a values call."}, "effect_size": {"research": "qualitative (leaf / honest stop)", "simple": "this is the honest stopping point"}, "source_type": "meta-analysis", "source_citation": "Dinesen et al. 2020.", "triggers_split_to": [], "tension_with": [], "source_strength": "thin", "evidence_type": "review", "source_cluster": "Dinesen-2020", "caveat": {"research": "Synthesis across many studies of varying design and quality.", "simple": "A round-up of many studies of mixed quality."}}, {"finding_id": "F-int-1", "node_id": "n_social_integration", "direction": "SUPPORTS", "claim_paragraph": {"research": "Economic and civic integration is largely generational and upward: NAS finds second-generation immigrants reach higher education, earnings and tax-paying than comparable third-plus-generation natives \u2014 assimilation works, over decades not years.", "simple": "Immigrants and their kids tend to catch up and move up: the US review found second-generation immigrants reach more education, higher pay, and pay more tax than long-settled locals \u2014 over decades, not years."}, "effect_size": {"research": "2nd gen exceeds comparable natives", "simple": "the children often do better than long-settled locals"}, "source_type": "systematic-review", "source_citation": "NAS 2016.", "triggers_split_to": [], "tension_with": [], "source_strength": "moderate", "evidence_type": "observational", "source_cluster": "NAS-2016", "caveat": {"research": "Correlational; selection and confounding (where immigrants settle, who is selected to migrate) are not fully ruled out.", "simple": "This is a pattern, not proof of cause \u2014 things like where immigrants settle, or who chooses to move, could be behind it."}}, {"finding_id": "F-int-2", "node_id": "n_social_integration", "direction": "COMPLICATES", "claim_paragraph": {"research": "Integration speed varies by origin, education, language distance and reception context; 'do immigrants integrate?' has no single answer without specifying which group and which dimension (labour market vs language vs intermarriage vs identity).", "simple": "How fast people settle in varies by where they came from, their schooling, language, and how they're received. 'Do immigrants fit in?' has no single answer without saying which group and which part of life (work, language, marriage, identity)."}, "effect_size": {"research": "qualitative", "simple": "qualitative"}, "source_type": "systematic-review", "source_citation": "NAS 2016; comparative migration literature.", "triggers_split_to": [], "tension_with": [], "source_strength": "thin", "evidence_type": "review", "source_cluster": "NAS-2016", "caveat": {"research": "Synthesis across many studies of varying design and quality.", "simple": "A round-up of many studies of mixed quality."}}, {"finding_id": "F-int-3", "node_id": "n_social_integration", "direction": "CHALLENGES", "claim_paragraph": {"research": "Where integration stalls \u2014 segregated low-opportunity neighbourhoods, weak labour-market access \u2014 second-generation outcomes can lag, and that stall is also what drives the local trust and (in Europe) crime associations. Integration is the mechanism the other social findings run through.", "simple": "Where fitting in stalls \u2014 cut-off neighbourhoods, few job routes \u2014 the second generation can fall behind, and that's also what drives the local trust and (in Europe) crime patterns. Settling in is the thread the other social effects run through."}, "effect_size": {"research": "qualitative; stalls localise harm", "simple": "when settling in stalls, problems cluster locally"}, "source_type": "single-study", "source_citation": "Dinesen et al. 2020; European crime reviews.", "triggers_split_to": [], "tension_with": [], "source_strength": "thin", "evidence_type": "observational", "source_cluster": "Dinesen-2020", "caveat": {"research": "Correlational; selection and confounding (where immigrants settle, who is selected to migrate) are not fully ruled out.", "simple": "This is a pattern, not proof of cause \u2014 things like where immigrants settle, or who chooses to move, could be behind it."}}, {"finding_id": "F-cr-4", "node_id": "n_social_crime", "direction": "SUPPORTS", "claim_paragraph": {"research": "Across 38 European countries (Eurostat 2017\u20132020), immigration is significantly and POSITIVELY associated with some specific offences once socioeconomic factors are included \u2014 notably sexual-violence rates (r \u2248 0.20) and theft. The association is country-level, cross-sectional and correlational, and is offence-specific rather than a uniform crime increase.", "simple": "Across 38 European countries, more immigration lined up with more of certain crimes \u2014 especially sexual violence and theft \u2014 even after accounting for income and other factors. This is a country-level pattern, not proof immigration caused it, and it varies by crime type."}, "effect_size": {"research": "r\u22480.20 sexual violence; positive for theft (country-level, cross-sectional)", "simple": "linked to more of certain crimes in Europe"}, "source_strength": "moderate", "source_type": "single-study", "source_citation": "Crime, Law and Social Change 2024 \u2014 38 European countries, Eurostat 2017\u20132020.", "triggers_split_to": [], "tension_with": ["F-cr-2", "F-cr-5"], "evidence_type": "observational", "source_cluster": "EuroCrime-2024", "caveat": {"research": "Correlational; selection and confounding (where immigrants settle, who is selected to migrate) are not fully ruled out.", "simple": "This is a pattern, not proof of cause \u2014 things like where immigrants settle, or who chooses to move, could be behind it."}}, {"finding_id": "F-cr-5", "node_id": "n_social_crime", "direction": "CHALLENGES", "claim_paragraph": {"research": "A district-level panel for Germany (2008\u20132019) that explicitly corrects for immigrants' non-random location choice finds NO significant positive relationship between immigrant share and total crime; effects average to roughly zero (positive in the early sub-period, negative/insignificant later), with only a specification-sensitive positive effect on drug offences. Identification-aware European evidence does not support a general crime increase.", "simple": "A careful German study that accounted for where immigrants choose to live found no overall rise in crime from immigration between 2008 and 2019 \u2014 only a small, shaky effect on drug offences. Careful European evidence doesn't back a general crime rise."}, "effect_size": {"research": "\u22480 overall after correcting for location selection", "simple": "no overall rise, once you account for where people settle"}, "source_strength": "moderate", "source_type": "single-study", "source_citation": "CESifo Working Paper / 'Do immigrants affect crime? Evidence for Germany' 2023 \u2014 district panel 2008\u20132019.", "triggers_split_to": [], "tension_with": ["F-cr-4"], "evidence_type": "quasi-experimental", "source_cluster": "Germany-CESifo", "caveat": {"research": "Uses a natural-experiment / identification strategy \u2014 stronger on causation but narrow in setting.", "simple": "Uses a real-world 'natural experiment,' so it's better at showing cause \u2014 but only for that setting."}}, {"finding_id": "F-geo-1", "node_id": "n_econ_wages_overall", "direction": "CHALLENGES", "claim_paragraph": {"research": "A comparative OECD/ILO synthesis across ten low- and middle-income destination countries found that 'immigration has a limited impact on the labour market outcomes of native-born workers' \u2014 the relationship between the immigrant-worker share and native employment is 'generally negligible in the partner countries'. This extends beyond the high-income (largely US) evidence that anchors this leaf: in LMIC destinations too, the overall native wage/employment effect is small, cutting against the claim that immigration lowers native wages/employment overall.", "simple": "A ten-country study of poorer destination countries (from Ghana to Thailand) found immigrants barely move local workers' wages or jobs overall \u2014 the effect was 'generally negligible'. So the 'immigrants drive down wages' claim looks weak not just in rich countries but in poorer ones too."}, "effect_size": {"research": "native labour-market impact 'limited'/'generally negligible' across ten LMIC partner countries; where impacts exist they are diverse and highly contextual", "simple": "negligible overall effect on native wages/jobs across ten poorer countries"}, "source_type": "systematic-review", "source_citation": "OECD/ILO 2018. How Immigrants Contribute to Developing Countries' Economies (ECLM programme, OECD Development Centre + ILO; ten LMIC partner countries: Argentina, Costa Rica, Cote d'Ivoire, Dominican Republic, Ghana, Kyrgyzstan, Nepal, Rwanda, South Africa, Thailand).", "triggers_split_to": [], "tension_with": ["F-wl-1"], "source_strength": "strong", "evidence_type": "review", "source_cluster": "oecd-ilo-devecon", "caveat": {"research": "'Negligible on average' can still hide sectoral or informal-market effects (the report notes impacts, where present, are diverse and contextual, and that adjustment can occur via employment where wages are rigid). Institutional note: the OECD-ILO DevEcon programme shares OECD provenance with the OECD-migration cluster used elsewhere in this tool \u2014 treat as partially non-independent.", "simple": "'No effect on average' can still hide harm in particular industries or informal jobs. Also, this is an OECD-linked source like another one already used here, so they aren't fully independent."}}, {"finding_id": "F-geo-2", "node_id": "n_econ_gdp_pc", "direction": "SUPPORTS", "claim_paragraph": {"research": "The same OECD/ILO synthesis estimates immigrants' contribution to GDP at about 1% (Ghana) to 19% (Cote d'Ivoire), averaging ~7%, with the contribution to value added exceeding immigrants' employment share in half the partner countries; it concludes 'overall, immigration is unlikely to depress GDP per capita', with per-capita contribution higher than the native-born in most partner countries. This extends the GDP-per-capita result beyond the OECD/high-income evidence to ten LMIC destinations.", "simple": "Across ten poorer destination countries, immigrants added roughly 1% (Ghana) to 19% (Cote d'Ivoire) of GDP, about 7% on average, and the report concludes immigration is 'unlikely to depress GDP per capita'. So the 'raises income per head, not just total output' finding also shows up outside rich countries."}, "effect_size": {"research": "immigrant GDP contribution ~1% (Ghana) to 19% (Cote d'Ivoire), average ~7%; 'immigration is unlikely to depress GDP per capita'", "simple": "~7% average GDP contribution; does not lower GDP per capita"}, "source_type": "systematic-review", "source_citation": "OECD/ILO 2018. How Immigrants Contribute to Developing Countries' Economies (ECLM programme, OECD Development Centre + ILO; ten LMIC partner countries: Argentina, Costa Rica, Cote d'Ivoire, Dominican Republic, Ghana, Kyrgyzstan, Nepal, Rwanda, South Africa, Thailand).", "triggers_split_to": [], "tension_with": ["F-gp-1"], "source_strength": "strong", "evidence_type": "review", "source_cluster": "oecd-ilo-devecon", "caveat": {"research": "GDP-share contributions are accounting estimates, not causal per-capita growth effects; productivity results were 'less clear'. Institutional note: shares OECD provenance with the OECD-migration cluster that supplies this leaf's other findings, so it is partially non-independent corroboration, not a fully separate body of work.", "simple": "These are accounting estimates of how much immigrants add, not proof they raise growth; the productivity side was murkier. And it's OECD-linked like the other sources here, so not fully independent."}}, {"finding_id": "F-geo-3", "node_id": "n_fiscal_lowskill", "direction": "COMPLICATES", "claim_paragraph": {"research": "In the OECD/ILO ten-country synthesis \u2014 where migration is predominantly lower-skilled \u2014 immigrants raise public revenues but 'the increase may not be always sufficient to offset the public expenditures they generate'; the net position is a deficit under 1% of GDP in two countries (Kyrgyzstan, Nepal) and net-positive in the other partner countries with data. The overall fiscal effect is small and context-dependent rather than a uniform net drain, complicating any general 'low-skilled immigrants are a net fiscal drain' reading with non-US evidence.", "simple": "In these ten mostly-lower-skilled-migration countries, immigrants paid in more but not always enough to cover what they cost \u2014 a small shortfall (under 1% of GDP) in Kyrgyzstan and Nepal, but net positive elsewhere. So 'low-skilled immigrants are a drain' isn't a universal rule; the effect is small and depends on the country."}, "effect_size": {"research": "net fiscal position small and mixed: deficit <1% of GDP in Kyrgyzstan and Nepal, net-positive in the other partner countries with data", "simple": "small, mixed fiscal impact \u2014 slight cost in two countries, net gain in the rest"}, "source_type": "systematic-review", "source_citation": "OECD/ILO 2018. How Immigrants Contribute to Developing Countries' Economies (ECLM programme, OECD Development Centre + ILO; ten LMIC partner countries: Argentina, Costa Rica, Cote d'Ivoire, Dominican Republic, Ghana, Kyrgyzstan, Nepal, Rwanda, South Africa, Thailand).", "triggers_split_to": [], "tension_with": ["F-fl-1"], "source_strength": "moderate", "evidence_type": "review", "source_cluster": "oecd-ilo-devecon", "caveat": {"research": "Immigrant skill mix in these countries is not identical to the US low-skilled cohort the leaf's other findings measure, so this is context-transportability evidence, not a direct like-for-like fiscal comparison. Institutional overlap with the OECD-migration cluster applies.", "simple": "The immigrants here aren't exactly the same group as the US low-skilled immigrants the other studies measured, so it's a rough comparison across contexts, not identical cases."}}], "tensions": [{"a": "F-wo-1", "b": "F-wl-1", "kind": "scope-aggregation", "note": {"research": "No measurable overall wage effect vs harm concentrated on low-skilled natives / prior immigrants \u2014 aggregate vs subgroup, not a true contradiction.", "simple": "One says no overall effect on pay; the other says real harm to the lowest-paid. It's the whole versus a specific group \u2014 not a true clash."}}, {"a": "F-fis-2", "b": "F-fl-1", "kind": "assumption-sensitivity", "note": {"research": "'Not heavier benefit users' vs a low-skill net drain \u2014 driven by the average- vs marginal-cost public-goods assumption.", "simple": "One says immigrants aren't a drain; the other says lower-skilled ones are. The difference is how you count shared government costs."}}, {"a": "F-fl-1", "b": "F-fl-2", "kind": "assumption-sensitivity", "note": {"research": "Same population: net drain (average-cost) vs net positive (marginal-cost). The accounting assumption alone flips the sign.", "simple": "Same people, opposite results \u2014 a cost or a gain \u2014 depending only on how you count shared costs."}}, {"a": "F-fhz-1", "b": "F-fhz-2", "kind": "assumption-sensitivity", "note": {"research": "Descendants make the long run look positive vs 75-yr projections being assumption-driven and manipulable.", "simple": "Counting immigrants' children makes the long run look good; but these long-range forecasts can be bent to almost any answer."}}, {"a": "F-cr-2", "b": "F-cr-4", "kind": "context-transportability", "note": {"research": "US: immigrants ~60% less likely incarcerated vs Europe: positive association for specific offences. Context differs; not a like-for-like clash.", "simple": "In the US immigrants are locked up far less; in Europe some crimes rise with immigration. Different places \u2014 not a head-to-head clash."}}, {"a": "F-cr-4", "b": "F-cr-5", "kind": "empirical-contradiction", "note": {"research": "European cross-national correlational positive vs German selection-corrected null \u2014 a genuine identification dispute about whether the association is causal.", "simple": "One European study finds a link to more crime; a more careful one finds none. They genuinely disagree on whether it's real."}}, {"a": "F-econ-1", "b": "F-tr-2", "kind": "cross-dimension", "note": {"research": "Economic case (\u2248no harm overall) and cohesion case (small local trust erosion) point different ways and CANNOT be netted empirically \u2014 the weighting is a value choice.", "simple": "The economy looks roughly unharmed, but local trust dips a little. These pull different ways and can't be added up \u2014 it's a values call."}}, {"a": "F-is-1", "b": "F-ic-3", "kind": "empirical-contradiction", "note": {"research": "Immigrants produce an outsized patent share vs possible marginal crowd-out of natives in fixed-slot systems.", "simple": "Immigrants invent a lot; but where slots are limited, they might crowd some locals out. Both can be partly true."}}, {"a": "F-wl-2", "b": "F-econ-3", "kind": "scope-aggregation", "note": {"research": "GDP-per-capita / surplus framing vs the claim that the surplus is a transfer from low-wage labour to employers \u2014 same facts, distributional reframing.", "simple": "One frames it as the economy gaining; the other as money moving from low-paid workers to employers. Same facts, different emphasis."}}, {"a": "F-tr-1", "b": "F-tr-3", "kind": "empirical-contradiction", "note": {"research": "Putnam's constrict claim vs segregation-not-diversity: is the driver ethnic mix itself, or how it is spatially sorted?", "simple": "Is it diversity itself that lowers trust, or the way neighbourhoods are split up? The studies point at different causes."}}, {"a": "F-geo-1", "b": "F-wl-1", "kind": "context-transportability", "note": {"research": "The US National Academies evidence (F-wl-1) finds the clearest native wage/employment pressure among prior immigrants and low-skilled natives; the OECD/ILO ten-country synthesis finds the native labour-market impact 'generally negligible' in LMIC destinations. Both can hold \u2014 a concentrated distributional effect in the US labour market and a small aggregate effect in labour markets with large informal sectors and different substitutability \u2014 but the wage-depression signal does not transport uniformly across destination contexts.", "simple": "US data show the sharpest wage pressure lands on earlier immigrants and low-skilled locals; the ten-country study finds barely any overall effect in poorer countries. The harm is real in some settings and faint in others \u2014 it doesn't travel evenly."}}, {"a": "F-geo-2", "b": "F-gp-1", "kind": "context-transportability", "note": {"research": "The OECD International Migration Outlook evidence (F-gp-1) supports a positive GDP-per-capita effect in high-income destinations; the OECD/ILO DevEcon synthesis (F-geo-2) reports that immigration is 'unlikely to depress GDP per capita' across ten LMIC destinations. The result appears to replicate across income settings \u2014 but the two draw on the same institution (OECD), so this is partially-non-independent corroboration rather than a fully separate confirmation.", "simple": "One OECD study finds immigrants lift income per head in rich countries; a second OECD-linked study finds they don't drag it down in poorer ones. The finding seems to hold across settings \u2014 but both come from OECD work, so they don't fully count as two independent confirmations."}}, {"a": "F-geo-3", "b": "F-fl-1", "kind": "context-transportability", "note": {"research": "The US-based net-fiscal-drain finding for low-skilled immigrants (F-fl-1) contrasts with the OECD/ILO ten-country result that the fiscal impact is small and mostly net-positive, with a sub-1%-of-GDP deficit in only two partner countries. The divergence reflects different tax-transfer systems, informal-sector shares, and public-goods provision \u2014 the 'net drain' conclusion is contingent on the fiscal architecture of the destination, not a universal property of low-skilled immigration.", "simple": "US figures say low-skilled immigrants cost more than they pay in; the ten-country study finds mostly the opposite, with a tiny shortfall in just two countries. It depends on each country's tax-and-benefit system \u2014 the 'drain' isn't a fixed fact about low-skilled immigrants everywhere."}}]};

const STR_RANK = { strong: 0, moderate: 1, thin: 2 };
const DIR_LABEL = { SUPPORTS: "FOR", CHALLENGES: "AGAINST", COMPLICATES: "COMPLICATES" };
const DIR_COLOR = { SUPPORTS: "#5c7a64", CHALLENGES: "#a85d52", COMPLICATES: "#9a8a55" };
const TEASER_KINDS = new Set(["cross-dimension", "empirical-contradiction"]);

function buildIndex(d) {
  const nodeById = {}; d.nodes.forEach(n => (nodeById[n.id] = n));
  const findingById = {}; d.findings.forEach(f => (findingById[f.finding_id] = f));
  const findingsByNode = {};
  d.findings.forEach(f => { (findingsByNode[f.node_id] ||= []).push(f); });
  const subtree = {};
  const collect = (id) => {
    if (subtree[id]) return subtree[id];
    const set = new Set((findingsByNode[id] || []).map(f => f.finding_id));
    (nodeById[id].children || []).forEach(c => collect(c).forEach(x => set.add(x)));
    return (subtree[id] = set);
  };
  d.nodes.forEach(n => collect(n.id));
  const tnAdj = {};
  d.tensions.forEach(t => {
    (tnAdj[t.a] ||= []).push({ partner: t.b, kind: t.kind, note: t.note });
    (tnAdj[t.b] ||= []).push({ partner: t.a, kind: t.kind, note: t.note });
  });
  return { nodeById, findingById, findingsByNode, subtree, tnAdj };
}

function orderFindings(list) {
  const rank = f => (STR_RANK[f.source_strength] ?? 1);
  const tag = list.map((f, i) => ({ f, i }));
  const by = (a, b) => rank(a.f) - rank(b.f) || a.i - b.i;
  const S = tag.filter(x => x.f.direction === "SUPPORTS").sort(by);
  const C = tag.filter(x => x.f.direction === "CHALLENGES").sort(by);
  const X = tag.filter(x => x.f.direction === "COMPLICATES").sort(by);
  const inter = []; let i = 0;
  while (i < S.length || i < C.length) { if (i < S.length) inter.push(S[i]); if (i < C.length) inter.push(C[i]); i++; }
  return [...inter, ...X].map(x => x.f);
}

const pick = (x, reg) => (x && typeof x === "object" && !Array.isArray(x) && ("research" in x))
  ? (x[reg] ?? x.research) : x;

const crumb = (n, reg) => n.role === "topic" ? "Start"
  : pick(n.question, reg).replace(/\?+$/, "").replace(/^(How|Does|What|Are|Do)\s+/i, "").trim().slice(0, 24);

export default function App() {
  const idx = useMemo(() => buildIndex(DATA), []);
  const { nodeById, findingById, findingsByNode, subtree, tnAdj } = idx;

  const [current, setCurrent] = useState("n_root");
  const [reg, setReg] = useState("research");
  const P = x => pick(x, reg);
  const [path, setPath] = useState(["n_root"]);
  const [phase, setPhase] = useState("reading");
  const [step, setStep] = useState(0);
  const [seen, setSeen] = useState({});
  const [conf, setConf] = useState({});
  const [, setChoices] = useState({});
  const [visited, setVisited] = useState({ n_root: true });
  const [teasers, setTeasers] = useState(null);
  const [pendingChild, setPendingChild] = useState(null);
  const [slider, setSlider] = useState(50);

  const node = nodeById[current];
  const ordered = useMemo(() => orderFindings(findingsByNode[current] || []), [current]);

  useEffect(() => {
    if (phase === "reading" && ordered[step]) {
      const fid = ordered[step].finding_id;
      setSeen(s => (s[fid] ? s : { ...s, [fid]: true }));
    }
  }, [current, phase, step, ordered]);

  function enter(nodeId, newPath) {
    const n = nodeById[nodeId];
    setCurrent(nodeId); setPath(newPath); setStep(0); setTeasers(null); setPendingChild(null);
    setVisited(v => (v[nodeId] ? v : { ...v, [nodeId]: true }));
    if (n.scored) {
      const c = conf[nodeId] || {};
      if (c.posterior != null) setPhase("stop");
      else if (c.prior != null) setPhase("reading");
      else { setPhase("prior"); setSlider(50); }
    } else {
      const comps = (findingsByNode[nodeId] || []).filter(f => f.direction === "COMPLICATES");
      setPhase(comps.every(f => seen[f.finding_id]) ? "depend" : "reading");
    }
  }

  function next() {
    if (step < ordered.length - 1) { setStep(step + 1); return; }
    if (node.scored) { setPhase("posterior"); setSlider(Math.round(((conf[current]?.prior) ?? 0.5) * 100)); }
    else setPhase("depend");
  }

  function chooseChild(childId) {
    setChoices(c => ({ ...c, [current]: childId }));
    const sibs = (node.children || []).filter(c => c !== childId);
    const seenIds = Object.keys(seen);
    const ts = [];
    sibs.forEach(sib => {
      const sf = subtree[sib] || new Set();
      seenIds.forEach(sid => (tnAdj[sid] || []).forEach(adj => {
        if (sf.has(adj.partner) && TEASER_KINDS.has(adj.kind))
          ts.push({ sibling: sib, label: nodeById[sib].question, note: adj.note, seenId: sid });
      }));
    });
    const uniq = [...new Map(ts.map(t => [t.sibling + t.note, t])).values()];
    if (uniq.length) { setTeasers(uniq); setPendingChild(childId); setPhase("teaser"); }
    else enter(childId, [...path, childId]);
  }

  const firedFor = fid => (tnAdj[fid] || []).filter(a => seen[a.partner] && a.partner !== fid);

  const seenCount = Object.keys(seen).length;
  const viewKey = current + "|" + phase + "|" + step + "|" + reg;

  // ---------- styles ----------
  const C = { bg: "#FAFAF8", ink: "#1b1a17", mut: "#9a978f", faint: "#c9c6bd", rule: "#e8e6df" };
  const serif = "Georgia, 'Times New Roman', serif";
  const mono = "ui-monospace, 'SF Mono', Menlo, monospace";
  const wrap = { minHeight: "100vh", background: C.bg, color: C.ink, display: "flex", flexDirection: "column", alignItems: "center", padding: "28px 20px 56px", boxSizing: "border-box" };
  const col = { width: "100%", maxWidth: 560, display: "flex", flexDirection: "column", alignItems: "center", textAlign: "center", flex: 1 };
  const label = { fontFamily: mono, fontSize: 11, letterSpacing: "0.16em", textTransform: "uppercase", color: C.mut };
  const claim = { fontFamily: serif, fontSize: 21, lineHeight: 1.5, margin: "18px 0 0", maxWidth: 520 };
  const small = { fontFamily: mono, fontSize: 11.5, color: C.mut, lineHeight: 1.6 };
  const btn = { fontFamily: mono, fontSize: 12, letterSpacing: "0.06em", padding: "11px 26px", borderRadius: 999, border: "1px solid " + C.ink, background: "transparent", color: C.ink, cursor: "pointer", marginTop: 30 };
  const linkBtn = { fontFamily: mono, fontSize: 11.5, color: C.mut, background: "none", border: "none", cursor: "pointer", letterSpacing: "0.04em" };

  function Slider(onCommit, priorMark) {
    return (
      <div style={{ width: "100%", maxWidth: 380, marginTop: 26 }}>
        <div style={{ fontFamily: serif, fontSize: 40, lineHeight: 1 }}>{slider}<span style={{ fontSize: 18, color: C.mut }}>%</span></div>
        {priorMark != null && <div style={{ ...small, marginTop: 4 }}>you arrived at {Math.round(priorMark * 100)}%</div>}
        <input type="range" min="0" max="100" value={slider} onChange={e => setSlider(+e.target.value)} className="bue-range" style={{ width: "100%", marginTop: 18 }} />
        <div style={{ display: "flex", justifyContent: "space-between", ...label, fontSize: 10 }}>
          <span>certainly false</span><span>certainly true</span>
        </div>
        <button className="bue-btn" style={btn} onClick={onCommit}>Continue</button>
      </div>
    );
  }

  function Finding(f) {
    const fired = firedFor(f.finding_id);
    return (
      <>
        <div style={{ ...label, color: DIR_COLOR[f.direction], display: "flex", gap: 8, justifyContent: "center", alignItems: "center" }}>
          <span style={{ width: 6, height: 6, borderRadius: 6, background: DIR_COLOR[f.direction], display: "inline-block" }} />
          {DIR_LABEL[f.direction]} · {f.evidence_type} · {f.source_strength}
        </div>
        <p style={claim}>{P(f.claim_paragraph)}</p>
        {P(f.effect_size) && P(f.effect_size) !== "qualitative" && <div style={{ ...small, marginTop: 12 }}>{P(f.effect_size)}</div>}
        <div style={{ ...small, fontStyle: "italic", marginTop: 12, maxWidth: 460 }}>{P(f.caveat)}</div>
        <div style={{ ...small, marginTop: 10, color: C.faint }}>{f.source_citation}</div>
        {fired.map((t, i) => (
          <div key={i} style={{ marginTop: 22, paddingTop: 16, borderTop: "1px solid " + C.rule, maxWidth: 460 }}>
            <div style={{ ...label, color: C.ink }}>tension · {t.kind}</div>
            <div style={{ fontFamily: serif, fontSize: 15, lineHeight: 1.5, marginTop: 8, color: "#444" }}>{P(t.note)}</div>
          </div>
        ))}
        <button className="bue-btn" style={btn} onClick={next}>{step < ordered.length - 1 ? "Next" : (node.scored ? "Rate again" : "So it depends →")}</button>
      </>
    );
  }

  function Heading() {
    if (node.role === "topic") return null;
    if (node.scored) return (
      <>
        <div style={{ ...small, marginBottom: 6 }}>{P(node.question)}</div>
        <div style={{ fontFamily: serif, fontSize: 23, lineHeight: 1.45, maxWidth: 520 }}>{P(node.claim_evaluated)}</div>
      </>
    );
    return <div style={{ fontFamily: serif, fontSize: 23, lineHeight: 1.45, maxWidth: 520 }}>{P(node.question)}</div>;
  }

  // ---------- body per phase ----------
  let body;
  if (phase === "reading") {
    body = <>
      {current === "n_root" && step === 0 && (
        <div style={{ marginBottom: 26 }}>
          <div style={{ fontFamily: serif, fontSize: 26, lineHeight: 1.35, maxWidth: 480 }}>A place to test a belief against the evidence.</div>
          <div style={{ ...small, marginTop: 16, maxWidth: 440, lineHeight: 1.7 }}>It won't hand you a verdict. It shows what the research says, where it's thin, and where it pulls in different directions — you do the believing.</div>
          <div style={{ ...small, marginTop: 16, maxWidth: 440, color: C.faint }}>Leaves out: housing, public-service load, gains to employers, origin-country effects, politics. Absence is scope, not proof of no effect.</div>
        </div>
      )}
      {current !== "n_root" && Heading()}
      <div style={{ height: 14 }} />
      {ordered[step] && Finding(ordered[step])}
    </>;
  } else if (phase === "depend") {
    const opts = node.children || [];
    const exploredN = opts.filter(cid => visited[cid]).length;
    body = <>
      {Heading()}
      <div style={{ ...label, marginTop: 30 }}>It depends. On what?</div>
      <div style={{ ...small, marginTop: 6 }}>Pick the aspect that matters most to you — the choice itself is telling.</div>
      {exploredN > 0 && <div style={{ ...small, marginTop: 4, color: C.faint }}>You've explored {exploredN} of {opts.length}.</div>}
      <div style={{ marginTop: 22, width: "100%", maxWidth: 460 }}>
        {opts.map(cid => {
          const vis = !!visited[cid];
          const post = conf[cid] && conf[cid].posterior;
          const tag = vis ? (post != null ? "visited · you left it at " + Math.round(post * 100) + "%" : "visited") : null;
          return (
            <button key={cid} className={"bue-choice" + (vis ? " bue-visited" : "")} onClick={() => chooseChild(cid)}>
              <span>
                <span className="bue-qtext">{P(nodeById[cid].question)}</span>
                {nodeById[cid].evidence_quality === "thin" && <span style={{ ...label, display: "block", marginTop: 5, color: C.faint }}>empirically thin</span>}
                {tag && <span className="bue-visited-tag">{tag}</span>}
              </span>
              <span className="bue-arrow">{vis ? "↺" : "→"}</span>
            </button>
          );
        })}
      </div>
    </>;
  } else if (phase === "teaser") {
    body = <>
      <div style={{ ...label }}>before you narrow</div>
      <div style={{ fontFamily: serif, fontSize: 21, lineHeight: 1.5, marginTop: 16, maxWidth: 500 }}>
        What you've seen pulls against evidence you're about to leave behind.
      </div>
      {teasers.map((t, i) => (
        <div key={i} style={{ marginTop: 20, maxWidth: 460 }}>
          <div style={{ ...label, color: C.ink }}>under → {crumb(nodeById[t.sibling], reg)}</div>
          <div style={{ fontFamily: serif, fontSize: 15, lineHeight: 1.5, marginTop: 8, color: "#444" }}>{P(t.note)}</div>
        </div>
      ))}
      <div style={{ ...small, marginTop: 22 }}>You can come back to it later — nothing you've read is lost.</div>
      <button className="bue-btn" style={btn} onClick={() => enter(pendingChild, [...path, pendingChild])}>Continue →</button>
    </>;
  } else if (phase === "prior") {
    body = <>
      {Heading()}
      <div style={{ ...label, marginTop: 28 }}>before the evidence</div>
      <div style={{ ...small, marginTop: 6 }}>How true does this feel right now?</div>
      {Slider(() => { setConf(c => ({ ...c, [current]: { ...(c[current] || {}), prior: slider / 100 } })); setPhase("reading"); setStep(0); })}
    </>;
  } else if (phase === "posterior") {
    body = <>
      {Heading()}
      <div style={{ ...label, marginTop: 28 }}>now, having read it</div>
      {Slider(() => { setConf(c => ({ ...c, [current]: { ...(c[current] || {}), posterior: slider / 100 } })); setPhase("stop"); }, conf[current]?.prior)}
    </>;
  } else if (phase === "stop") {
    const c = conf[current] || {};
    const d = c.posterior != null && c.prior != null ? Math.round((c.posterior - c.prior) * 100) : null;
    const seenHere = (findingsByNode[current] || []).map(f => f.finding_id);
    const tens = [];
    seenHere.forEach(fid => firedFor(fid).forEach(t => tens.push(t)));
    const uniqT = [...new Map(tens.map(t => [P(t.note), t])).values()];
    const parentFork = [...path].reverse().find(id => !nodeById[id].scored);
    const depObj = node.depends_on;
    const isLeafStop = depObj && (depObj.research || "").startsWith("LEAF");
    body = <>
      {Heading()}
      <div style={{ marginTop: 26, paddingTop: 20, borderTop: "1px solid " + C.rule, maxWidth: 480 }}>
        <div style={{ ...label }}>where the research runs out</div>
        <div style={{ fontFamily: serif, fontSize: 16, lineHeight: 1.6, marginTop: 12, color: "#3a3a36" }}>
          {isLeafStop
            ? P(depObj).replace(/^LEAF:\s*/, "")
            : "This is the edge of what the evidence settles. What's left is a judgment about how much weight to give each piece — a values question, not an empirical one."}
        </div>
      </div>
      {d != null && (
        <div style={{ marginTop: 24 }}>
          <div style={{ ...label }}>your move</div>
          <div style={{ fontFamily: serif, fontSize: 22, marginTop: 8 }}>
            {Math.round(c.prior * 100)}% <span style={{ color: C.mut }}>→</span> {Math.round(c.posterior * 100)}%
          </div>
          <div style={{ ...small, marginTop: 4 }}>{d === 0 ? "held steady" : (d > 0 ? "+" : "") + d + " points"}</div>
        </div>
      )}
      {uniqT.length > 0 && (
        <div style={{ marginTop: 24, maxWidth: 460 }}>
          <div style={{ ...label }}>still unresolved</div>
          {uniqT.map((t, i) => <div key={i} style={{ fontFamily: serif, fontSize: 14.5, lineHeight: 1.5, marginTop: 10, color: "#555" }}>{P(t.note)}</div>)}
        </div>
      )}
      <div style={{ marginTop: 30, display: "flex", gap: 22 }}>
        {parentFork && parentFork !== current &&
          <button className="bue-link" onClick={() => { const i = path.indexOf(parentFork); enter(parentFork, path.slice(0, i + 1)); }}>← explore another branch</button>}
      </div>
    </>;
  }

  return (
    <div style={wrap}>
      <style>{`
        @keyframes bueEnter { from { opacity: 0; transform: translateY(12px); } to { opacity: 1; transform: none; } }
        .bue-fade { animation: bueEnter .44s cubic-bezier(.2,.7,.2,1) both; }
        @media (prefers-reduced-motion: reduce) { .bue-fade { animation: none; } }
        .bue-range { -webkit-appearance: none; appearance: none; height: 2px; background: ${C.faint}; outline: none; border-radius: 2px; }
        .bue-range::-webkit-slider-thumb { -webkit-appearance: none; width: 18px; height: 18px; border-radius: 50%; background: ${C.ink}; cursor: pointer; }
        .bue-range::-moz-range-thumb { width: 18px; height: 18px; border: none; border-radius: 50%; background: ${C.ink}; cursor: pointer; }
        .bue-crumb { text-decoration: underline; text-underline-offset: 2px; text-decoration-style: dotted; text-decoration-color: ${C.faint}; }
        .bue-crumb:hover { color: ${C.ink} !important; text-decoration-color: ${C.ink}; }
        .bue-crumb.bue-current { text-decoration: none; cursor: default; }
        .bue-btn { transition: background .15s, color .15s; }
        .bue-btn:hover { background: ${C.ink}; color: ${C.bg}; }
        .bue-link { color: ${C.ink}; background: none; border: none; padding: 0; cursor: pointer; font-family: ${mono}; font-size: 11.5px; letter-spacing: .04em; text-decoration: underline; text-underline-offset: 3px; }
        .bue-link:hover { opacity: .6; }
        .bue-choice { display: flex; align-items: center; justify-content: center; gap: 12px; width: 100%; box-sizing: border-box; text-align: center; background: #ffffff; border: 1px solid ${C.rule}; border-radius: 12px; padding: 16px 18px; margin-top: 10px; cursor: pointer; font-family: ${serif}; font-size: 17px; color: ${C.ink}; line-height: 1.4; transition: border-color .15s, background .15s, box-shadow .15s; }
        .bue-choice:hover { border-color: ${C.ink}; box-shadow: 0 1px 0 ${C.ink}; }
        .bue-choice .bue-arrow { color: ${C.mut}; font-family: ${mono}; font-size: 13px; }
        .bue-choice:hover .bue-arrow { color: ${C.ink}; }
        .bue-choice.bue-visited { background: #f2f3f6; border-color: #dcdde6; }
        .bue-choice.bue-visited .bue-qtext { color: ${C.mut}; }
        .bue-choice.bue-visited:hover { border-color: #6a6f86; box-shadow: 0 1px 0 #6a6f86; }
        .bue-visited-tag { display: block; margin-top: 6px; font-family: ${mono}; font-size: 10px; letter-spacing: .12em; text-transform: uppercase; color: #6a6f86; }
        .bue-seg { display: inline-flex; border: 1px solid ${C.rule}; border-radius: 999px; overflow: hidden; }
        .bue-seg button { font-family: ${mono}; font-size: 10.5px; letter-spacing: .08em; text-transform: uppercase; padding: 5px 13px; background: none; border: none; cursor: pointer; color: ${C.mut}; transition: background .15s, color .15s; }
        .bue-seg button:hover { color: ${C.ink}; }
        .bue-seg button.bue-on { background: ${C.ink}; color: ${C.bg}; }
      `}</style>

      {/* language toggle */}
      <div style={{ width: "100%", maxWidth: 560, display: "flex", justifyContent: "center", alignItems: "center", gap: 10, marginBottom: 18 }}>
        <span style={{ ...label, fontSize: 10, color: C.faint }}>language</span>
        <div className="bue-seg">
          {[["research", "Research"], ["simple", "Plain"]].map(([k, lab]) => (
            <button key={k} className={reg === k ? "bue-on" : ""} onClick={() => setReg(k)}>{lab}</button>
          ))}
        </div>
      </div>

      {/* breadcrumb */}
      <div style={{ width: "100%", maxWidth: 560, display: "flex", justifyContent: "center", flexWrap: "wrap", gap: 6, marginBottom: 30 }}>
        {path.map((id, i) => (
          <span key={id} style={{ ...label, fontSize: 10.5 }}>
            {i > 0 && <span style={{ color: C.faint, margin: "0 6px" }}>{"›"}</span>}
            <button className={"bue-crumb" + (i === path.length - 1 ? " bue-current" : "")}
              onClick={() => { if (i !== path.length - 1) enter(id, path.slice(0, i + 1)); }}
              style={{ background: "none", border: "none", padding: 0, cursor: "pointer", color: i === path.length - 1 ? C.ink : C.mut, ...label, fontSize: 10.5 }}>
              {crumb(nodeById[id], reg)}
            </button>
          </span>
        ))}
      </div>

      <div style={col}>
        <div key={viewKey} className="bue-fade" style={{ display: "flex", flexDirection: "column", alignItems: "center", width: "100%" }}>
          {body}
        </div>
      </div>

      <div style={{ ...label, fontSize: 10, color: C.faint, marginTop: 40 }}>{seenCount} of {DATA.findings.length} findings seen</div>
    </div>
  );
}
